Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]

[GQL-OP cleanup_pre_main]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartName: "default" cultureName: "en-US" currencyCode: "USD" }) { id itemsCount } }
[GQL-EXEC cleanup_pre_main]

[GQL-OP cleanup_pre_saved]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartName: "Saved for later" cultureName: "en-US" currencyCode: "USD" }) { id itemsCount } }
[GQL-EXEC cleanup_pre_saved]

[GQL-OP add_a]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}"
      userId: "{{USER_ID}}"
      productId: "{{ring_id}}"
      quantity: 1
      currencyCode: "USD"
      cultureName: "en-US"
      configurationSections: [{ sectionId: "{{section_text_id}}" type: "Text" customText: "{{text_a}}" }]
    }) { id itemsCount }
  }
[GQL-EXEC add_a]

[GQL-OP add_b]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}"
      userId: "{{USER_ID}}"
      productId: "{{ring_id}}"
      quantity: 1
      currencyCode: "USD"
      cultureName: "en-US"
      configurationSections: [{ sectionId: "{{section_text_id}}" type: "Text" customText: "{{text_b}}" }]
    }) { id itemsCount }
  }
[GQL-EXEC add_b]

[GQL-OP add_c]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}"
      userId: "{{USER_ID}}"
      productId: "{{ring_id}}"
      quantity: 1
      currencyCode: "USD"
      cultureName: "en-US"
      configurationSections: [{ sectionId: "{{section_text_id}}" type: "Text" customText: "{{text_c}}" }]
    }) { id itemsCount }
  }
[GQL-EXEC add_c]

[GQL-OP read_cart_after_adds]
  query {
    cart(storeId: "{{STORE_ID}}" currencyCode: "USD" userId: "{{USER_ID}}" cultureName: "en-US" cartName: "default") {
      id
      itemsCount
      items {
        id
        productId
        quantity
        configurationItems { id sectionId type customText productId selectedForCheckout }
      }
    }
  }
[GQL-EXEC read_cart_after_adds]
[GQL-CAPTURE read_cart_after_adds.data.cart.id → CART_ID]
[GQL-CAPTURE read_cart_after_adds.data.cart.items.0.id → LINE_0]
[GQL-CAPTURE read_cart_after_adds.data.cart.items.1.id → LINE_1]
[GQL-CAPTURE read_cart_after_adds.data.cart.items.2.id → LINE_2]

[GQL-OP move_all_saved]
  mutation {
    moveToSavedForLater(command: {
      storeId: "{{STORE_ID}}"
      userId: "{{USER_ID}}"
      cartId: "{{CART_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      lineItemIds: ["{{LINE_0}}", "{{LINE_1}}", "{{LINE_2}}"]
    }) {
      cart { id itemsCount items { id } }
      list {
        id
        itemsCount
        items {
          id
          productId
          quantity
          configurationItems { id sectionId type customText productId selectedForCheckout }
        }
      }
    }
  }
[GQL-EXEC move_all_saved]

[GQL-OP cleanup_post_main]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartName: "default" cultureName: "en-US" currencyCode: "USD" }) { id itemsCount } }
[GQL-EXEC cleanup_post_main]

[GQL-OP cleanup_post_saved]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartName: "Saved for later" cultureName: "en-US" currencyCode: "USD" }) { id itemsCount } }
[GQL-EXEC cleanup_post_saved]

