[GQL-OP read_cart]
  query {
    cart(storeId: "{{STORE_ID}}" currencyCode: "USD" userId: "{{USER_ID}}" cultureName: "en-US" cartName: "default") {
      id
      items { id configurationItems { customText } }
    }
  }
[GQL-EXEC read_cart]
[GQL-CAPTURE read_cart.data.cart.id → CART_ID]
[GQL-CAPTURE read_cart.data.cart.items.0.id → LINE_0]
[GQL-CAPTURE read_cart.data.cart.items.1.id → LINE_1]
[GQL-CAPTURE read_cart.data.cart.items.2.id → LINE_2]

[GQL-OP move_all_saved]
  mutation {
    moveToSavedForLater(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartId: "{{CART_ID}}" currencyCode: "USD" cultureName: "en-US"
      lineItemIds: ["{{LINE_0}}", "{{LINE_1}}", "{{LINE_2}}"]
    }) {
      cart { id }
      list { id items { id configurationItems { customText } } }
    }
  }
[GQL-EXEC move_all_saved]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.0.id → SAVED_0_ID]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.0.configurationItems.0.customText → SAVED_0_TEXT]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.1.id → SAVED_1_ID]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.1.configurationItems.0.customText → SAVED_1_TEXT]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.2.id → SAVED_2_ID]
[GQL-CAPTURE move_all_saved.data.moveToSavedForLater.list.items.2.configurationItems.0.customText → SAVED_2_TEXT]

[GQL-OP move_b_back]
  mutation {
    moveFromSavedForLater(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartId: "{{CART_ID}}" currencyCode: "USD" cultureName: "en-US"
      lineItemIds: ["{{SAVED_0_ID}}"]
    }) {
      cart {
        id
        itemsCount
        items {
          id
          productId
          quantity
          configurationItems { sectionId type customText productId selectedForCheckout }
        }
      }
      list {
        id
        itemsCount
        items { id configurationItems { customText } }
      }
    }
  }
[GQL-EXEC move_b_back]

[GQL-OP cleanup_post_main]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartName: "default" cultureName: "en-US" currencyCode: "USD" }) { id itemsCount } }
